# Stack ADT — user only sees the interface, not the implementation
class StackADT:
    def push(self, item): pass    # Add to top
    def pop(self): pass           # Remove from top
    def peek(self): pass          # View top without removing
    def is_empty(self): pass      # Check if empty

# One implementation using Python list
class ArrayStack(StackADT):
    def __init__(self):
        self._data = []
    def push(self, item):
        self._data.append(item)
    def pop(self):
        return self._data.pop()
    def peek(self):
        return self._data[-1]
    def is_empty(self):
        return len(self._data) == 0

# ADT: Queue (defines the interface)
from abc import ABC, abstractmethod

class QueueADT(ABC):
    @abstractmethod
    def enqueue(self, item): pass
    @abstractmethod
    def dequeue(self): pass
    @abstractmethod
    def front(self): pass
    @abstractmethod
    def is_empty(self): pass

# Data Structure 1: Array-based Queue
class ArrayQueue(QueueADT):
    def __init__(self):
        self._data = []
    def enqueue(self, item):
        self._data.append(item)
    def dequeue(self):
        return self._data.pop(0)
    def front(self):
        return self._data[0]
    def is_empty(self):
        return len(self._data) == 0

# Data Structure 2: Linked List Queue
class LinkedQueue(QueueADT):
    # Different internal structure, same interface!
    pass

# Encapsulation in a Stack ADT using Python
class Stack:
    def __init__(self):
        self.__data = []      # Private: name-mangled to _Stack__data
        self.__size = 0       # Users cannot access this directly

    def push(self, item):
        self.__data.append(item)
        self.__size += 1

    def pop(self):
        if self.is_empty():
            raise IndexError('Stack underflow')
        self.__size -= 1
        return self.__data.pop()

    def peek(self):
        if self.is_empty():
            raise IndexError('Stack is empty')
        return self.__data[-1]

    def is_empty(self):
        return self.__size == 0

    def size(self):
        return self.__size

s = Stack()
s.push(10)
s.push(20)
print(s.peek())       # 20
# print(s.__data)     # AttributeError! Encapsulation enforced

# Property decorators for controlled access
class BoundedList:
    def __init__(self, capacity):
        self.__items = []
        self.__capacity = capacity

    @property
    def capacity(self):
        return self.__capacity   # Read-only access

    @property
    def count(self):
        return len(self.__items) # Read-only computed property

    def add(self, item):
        if self.count >= self.__capacity:
            raise OverflowError('List is full')
        self.__items.append(item)

bl = BoundedList(3)
bl.add(1); bl.add(2)
print(bl.capacity)  # 3
print(bl.count)     # 2
# bl.capacity = 10  # AttributeError — read-only property!

# Information hiding through abstract interface
from abc import ABC, abstractmethod

class SortedContainer(ABC):
    """Stable interface — users depend only on this"""
    @abstractmethod
    def insert(self, value): pass
    @abstractmethod
    def remove(self, value): pass
    @abstractmethod
    def contains(self, value): pass
    @abstractmethod
    def minimum(self): pass

# Implementation A: BST-based (hidden from user)
class BSTContainer(SortedContainer):
    def __init__(self):
        self._root = None  # User doesn't know this is a BST!
    def insert(self, value): pass  # BST insert logic
    def remove(self, value): pass
    def contains(self, value): pass
    def minimum(self): pass

# Implementation B: Sorted list-based (swappable!)
class SortedListContainer(SortedContainer):
    def __init__(self):
        self._data = []   # User doesn't know this is a list!
    def insert(self, value):
        import bisect
        bisect.insort(self._data, value)
    def remove(self, value): self._data.remove(value)
    def contains(self, value): return value in self._data
    def minimum(self): return self._data[0]

# Classification of List ADT operations
class ListADT:
    # === CONSTRUCTORS ===
    def __init__(self):
        """Create a new empty list"""
        self._data = []
        self._size = 0

    @classmethod
    def from_iterable(cls, iterable):
        """Factory constructor from existing data"""
        obj = cls()
        for item in iterable:
            obj.append(item)
        return obj

    # === ACCESSORS (read-only, no state change) ===
    def size(self): return self._size
    def is_empty(self): return self._size == 0
    def get(self, index): return self._data[index]
    def find(self, value): return self._data.index(value)
    def contains(self, value): return value in self._data

    # === MUTATORS (modify state) ===
    def append(self, value):
        self._data.append(value)
        self._size += 1
    def insert(self, index, value):
        self._data.insert(index, value)
        self._size += 1
    def delete(self, index):
        self._data.pop(index)
        self._size -= 1
    def clear(self):
        self._data = []
        self._size = 0

# Demonstrating all core List ADT operations
class ListADT:
    def __init__(self): self._d = []
    def insert(self, pos, val): self._d.insert(pos, val)
    def delete(self, pos): self._d.pop(pos)
    def get(self, pos): return self._d[pos]
    def set(self, pos, val): self._d[pos] = val
    def find(self, val):
        try: return self._d.index(val)
        except ValueError: return -1
    def size(self): return len(self._d)
    def is_empty(self): return len(self._d) == 0
    def clear(self): self._d.clear()
    def print_list(self): print(self._d)

L = ListADT()
L.insert(0, 10)  # [10]
L.insert(1, 30)  # [10, 30]
L.insert(1, 20)  # [10, 20, 30]
L.print_list()   # [10, 20, 30]
print(L.get(2))  # 30
print(L.find(20)) # 1
L.set(0, 5)      # [5, 20, 30]
L.delete(1)      # [5, 30]
print(L.size())  # 2

# Preconditions and error handling
class SafeList:
    def __init__(self): self._data = []

    def get(self, index):
        # Precondition: 0 <= index < size
        if not (0 <= index < len(self._data)):
            raise IndexError(f'Index {index} out of range [0, {len(self._data)-1}]')
        return self._data[index]

    def delete(self, index):
        if self.is_empty():
            raise IndexError('Cannot delete from empty list')
        if not (0 <= index < len(self._data)):
            raise IndexError(f'Index {index} out of range')
        return self._data.pop(index)

    def is_empty(self): return len(self._data) == 0

sl = SafeList()
try:
    sl.get(0)  # Raises IndexError — list is empty!
except IndexError as e:
    print(f'Error: {e}')

# Complete List ADT interface using Python ABC
from abc import ABC, abstractmethod
from typing import Any, Optional

class ListADT(ABC):
    """Abstract interface for the List ADT.
    Any concrete implementation must fulfill all these contracts.
    """

    @abstractmethod
    def insert(self, position: int, element: Any) -> None:
        """Insert element at position. Shifts right.
        Pre: 0 <= position <= size()
        Post: size increases by 1; get(position) == element
        """
        pass

    @abstractmethod
    def delete(self, position: int) -> Any:
        """Remove and return element at position.
        Pre: 0 <= position < size()
        Post: size decreases by 1
        """
        pass

    @abstractmethod
    def get(self, position: int) -> Any:
        """Return element at position without removing.
        Pre: 0 <= position < size()
        """
        pass

    @abstractmethod
    def find(self, element: Any) -> int:
        """Return first index of element, or -1 if not found."""
        pass

    @abstractmethod
    def size(self) -> int:
        """Return number of elements. Always >= 0."""
        pass

    # Concrete convenience method built on abstract operations
    def is_empty(self) -> bool:
        return self.size() == 0

    def append(self, element: Any) -> None:
        self.insert(self.size(), element)

    def prepend(self, element: Any) -> None:
        self.insert(0, element)

# Concrete implementation 1: Array-based
class ArrayList(ListADT):
    def __init__(self):
        self._data = []

    def insert(self, position, element):
        if not (0 <= position <= len(self._data)):
            raise IndexError('Invalid position')
        self._data.insert(position, element)

    def delete(self, position):
        if not (0 <= position < len(self._data)):
            raise IndexError('Invalid position')
        return self._data.pop(position)

    def get(self, position):
        return self._data[position]

    def find(self, element):
        try: return self._data.index(element)
        except ValueError: return -1

    def size(self): return len(self._data)

    def __repr__(self): return f'ArrayList({self._data})'
